export interface Prompt {
  id: string
  category: string
  title: string
  description: string
  prompt: string
  tags: string[]
  difficulty: 'starter' | 'intermediate' | 'advanced'
  gordonBoost: boolean
}

// 50 KAM prompts — full bilingual content (FR + EN)

const promptsFR: Prompt[] = [
  // ACCOUNT ANALYSIS (9)
  { id: 'aa-001', category: 'account-analysis', title: 'Analyse 360° du compte', description: 'Obtenez une vue complète de votre compte stratégique en quelques minutes.', prompt: 'Tu es un expert KAM. Analyse ce compte stratégique de manière exhaustive.\n\nCompte : [NOM DU COMPTE]\nSecteur : [SECTEUR]\nCA actuel : [MONTANT]\nAncienneté relation : [DURÉE]\n\nFournis :\n1. Forces de la relation actuelle\n2. Faiblesses identifiées\n3. Opportunités de croissance\n4. Menaces (concurrence, budget, réorg)\n5. Score de santé du compte (1-10)\n6. 3 actions prioritaires pour les 30 prochains jours', tags: ['SWOT', 'analyse', 'stratégie'], difficulty: 'starter', gordonBoost: true },
  { id: 'aa-002', category: 'account-analysis', title: 'Identifier le potentiel inexploité', description: "Découvrez les opportunités d'expansion cachées dans vos comptes existants.", prompt: "Tu es un expert KAM spécialisé dans l'expansion de comptes.\n\nCompte : [NOM]\nProduits/services actuellement vendus : [LISTE]\nDépartements touchés : [LISTE]\nCA actuel : [MONTANT]\n\nAnalyse :\n1. Quels départements n'utilisent pas encore nos solutions ?\n2. Quels produits/services complémentaires pourraient être proposés ?\n3. Y a-t-il des filiales ou entités non adressées ?\n4. Estime le potentiel de croissance en % et en valeur\n5. Propose une stratégie de pénétration en 3 étapes", tags: ['expansion', 'upsell', 'cross-sell'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'aa-003', category: 'account-analysis', title: 'Analyse concurrentielle sur le compte', description: 'Évaluez la position de vos concurrents chez votre client.', prompt: "Tu es un stratège KAM. Analyse la position concurrentielle sur ce compte.\n\nCompte : [NOM]\nConcurrents identifiés chez le client : [LISTE]\nNotre part de marché estimée : [%]\n\nFournis :\n1. Matrice de comparaison (nous vs chaque concurrent) sur 5 critères\n2. Points de vulnérabilité de chaque concurrent\n3. Notre avantage compétitif différenciant\n4. Risque de déplacement (1-10)\n5. Stratégie défensive recommandée\n6. Stratégie offensive pour gagner des parts", tags: ['concurrence', 'défensif', 'offensif'], difficulty: 'advanced', gordonBoost: false },
  { id: 'aa-004', category: 'account-analysis', title: "Comprendre l'organigramme décisionnel", description: "Décryptez la structure de décision de votre compte.", prompt: "Tu es un expert en vente complexe B2B. Aide-moi à comprendre la structure décisionnelle de ce compte.\n\nCompte : [NOM]\nSecteur : [SECTEUR]\nTaille : [EFFECTIF]\nType d'achat : [NOUVEAU / RENOUVELLEMENT / EXTENSION]\n\nDécris :\n1. Les rôles typiques impliqués dans ce type de décision\n2. Le processus de décision probable (étapes, timeline)\n3. Les critères de décision par rôle (technique, financier, stratégique)\n4. Comment identifier le vrai décideur vs le signataire\n5. Questions à poser pour cartographier le circuit de décision", tags: ['décision', 'organigramme', 'vente complexe'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'aa-005', category: 'account-analysis', title: 'Audit de la relation client', description: "Évaluez la qualité et la profondeur de votre relation.", prompt: "Tu es un consultant KAM senior. Aide-moi à auditer la qualité de ma relation avec ce compte.\n\nCompte : [NOM]\nFréquence de contact : [HEBDO/MENSUEL/TRIMESTRIEL]\nNombre de contacts actifs : [N]\nNiveaux hiérarchiques touchés : [OPÉRATIONNEL/MANAGEMENT/DIRECTION]\n\nÉvalue :\n1. Score de profondeur relationnelle (1-10) avec justification\n2. Gaps identifiés (niveaux non couverts, départements absents)\n3. Risque de dépendance à un seul contact\n4. Plan d'action pour élargir et approfondir la relation\n5. Fréquence de contact recommandée par niveau", tags: ['relation', 'audit', 'contacts'], difficulty: 'starter', gordonBoost: false },
  { id: 'aa-006', category: 'account-analysis', title: 'Analyse des enjeux business du client', description: "Comprenez les priorités stratégiques de votre client pour mieux vous positionner.", prompt: "Tu es un analyste business B2B. Aide-moi à comprendre les enjeux stratégiques de mon client.\n\nClient : [NOM]\nSecteur : [SECTEUR]\nDernières actualités connues : [RÉSUMÉ]\n\nAnalyse :\n1. Les 3 priorités stratégiques probables de ce client\n2. Les pressions externes (réglementation, concurrence, marché)\n3. Les défis internes probables (transformation, réduction de coûts, croissance)\n4. Comment notre solution s'aligne avec ces enjeux\n5. Comment reformuler notre proposition de valeur en langage client", tags: ['stratégie', 'business', 'valeur'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'aa-007', category: 'account-analysis', title: 'Analyse du risque de churn', description: "Identifiez les signaux d'alerte avant de perdre un compte.", prompt: "Tu es un expert en rétention de comptes stratégiques. Aide-moi à évaluer le risque de churn.\n\nCompte : [NOM]\nCA annuel : [MONTANT]\nDate de renouvellement : [DATE]\nSignaux observés : [LISTE : ex. moins de réunions, demandes de benchmark, changement de sponsor...]\n\nFournis :\n1. Score de risque churn (1-10) avec justification\n2. Classification des signaux (rouge / orange / vert)\n3. Causes profondes probables\n4. Plan de rétention d'urgence (actions J+7, J+30, J+60)\n5. Argumentaire de valeur à préparer pour la prochaine réunion", tags: ['churn', 'rétention', 'risque'], difficulty: 'advanced', gordonBoost: true },
  { id: 'aa-008', category: 'account-analysis', title: 'Préparer un executive summary du compte', description: "Créez un résumé exécutif pour votre direction ou pour le client.", prompt: "Tu es un KAM senior qui doit présenter un compte à sa direction. Génère un executive summary.\n\nCompte : [NOM]\nCA : [MONTANT]\nProduits : [LISTE]\nHistorique : [RÉSUMÉ EN 2-3 LIGNES]\n\nStructure le résumé en :\n1. Vue d'ensemble (2 phrases max)\n2. Métriques clés (CA, marge, satisfaction, ancienneté)\n3. Faits marquants du dernier trimestre\n4. Risques et opportunités\n5. Recommandation stratégique\n6. Prochaines étapes\n\nTon : professionnel, concis, orienté décision.", tags: ['executive', 'résumé', 'direction'], difficulty: 'starter', gordonBoost: false },
  { id: 'aa-009', category: 'account-analysis', title: "Cartographier la chaîne de valeur du client", description: "Comprenez comment votre client crée de la valeur pour mieux vous positionner.", prompt: "Tu es un consultant en stratégie B2B. Aide-moi à cartographier la chaîne de valeur de mon client.\n\nClient : [NOM]\nSecteur : [SECTEUR]\nActivité principale : [DESCRIPTION]\n\nDécris :\n1. Les étapes clés de la chaîne de valeur du client\n2. Où nous intervenons actuellement\n3. Où nous pourrions intervenir (zones non adressées)\n4. L'impact de notre solution sur la chaîne de valeur\n5. Comment quantifier cet impact en termes business (ROI, TCO, productivité)", tags: ['chaîne de valeur', 'positionnement', 'ROI'], difficulty: 'advanced', gordonBoost: false },

  // QBR (8)
  { id: 'qbr-001', category: 'qbr', title: 'Structure complète de QBR', description: "Générez un plan de QBR professionnel en quelques minutes.", prompt: "Tu es un expert en revues stratégiques de comptes. Aide-moi à structurer ma prochaine QBR.\n\nCompte : [NOM]\nParticipants côté client : [NOMS ET RÔLES]\nObjectif principal : [RÉTENTION / EXPANSION / REDRESSEMENT]\n\nGénère un plan de QBR complet :\n1. Slide d'ouverture (agenda + objectifs)\n2. Bilan du trimestre (résultats vs objectifs)\n3. Valeur délivrée (métriques d'impact)\n4. Incidents et résolutions\n5. Vision stratégique (prochains 90 jours)\n6. Opportunités identifiées\n7. Plan d'action conjoint\n8. Prochaines étapes\n\nPour chaque section, donne le contenu clé et les points de discussion.", tags: ['QBR', 'structure', 'trimestre'], difficulty: 'starter', gordonBoost: true },
  { id: 'qbr-002', category: 'qbr', title: 'Préparer les questions difficiles de QBR', description: "Anticipez les questions que votre client va poser et préparez vos réponses.", prompt: "Tu es un coach de KAMs expérimenté. Mon client va me poser des questions difficiles lors de ma prochaine QBR.\n\nContexte : [RÉSUMÉ DE LA SITUATION]\nPoints sensibles connus : [LISTE]\n\nGénère :\n1. Les 10 questions les plus probables du client\n2. Pour chaque question : une réponse structurée (acknowledge → explain → action)\n3. Les pièges à éviter\n4. Comment transformer une critique en opportunité\n5. Phrases de transition pour garder le contrôle de la discussion", tags: ['QBR', 'objections', 'préparation'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'qbr-003', category: 'qbr', title: "Script d'ouverture de QBR", description: "Démarrez votre QBR avec impact et crédibilité.", prompt: "Tu es un expert en communication exécutive. Rédige un script d'ouverture de QBR.\n\nCompte : [NOM]\nParticipant le plus senior côté client : [NOM, TITRE]\nTon de la relation : [EXCELLENT / BON / TENDU / NOUVEAU]\n\nLe script doit :\n1. Durer 2-3 minutes max\n2. Remercier et contextualiser\n3. Rappeler les objectifs communs\n4. Annoncer l'agenda avec les bénéfices pour le client\n5. Créer de l'engagement dès le départ\n\nAdapte le ton au niveau de la relation.", tags: ['QBR', 'script', 'ouverture'], difficulty: 'starter', gordonBoost: false },
  { id: 'qbr-004', category: 'qbr', title: 'Quantifier la valeur délivrée', description: "Transformez vos actions en métriques d'impact pour impressionner en QBR.", prompt: "Tu es un expert en value selling. Aide-moi à quantifier la valeur que nous avons délivrée ce trimestre.\n\nCompte : [NOM]\nActions réalisées : [LISTE DES ACTIONS/PROJETS DU TRIMESTRE]\nMétriques disponibles : [LISTE]\n\nPour chaque action :\n1. Identifie la métrique d'impact la plus pertinente\n2. Quantifie en € ou en % d'amélioration\n3. Formule la phrase d'impact (\"Grâce à X, vous avez gagné Y\")\n4. Si pas de métrique dure : propose un proxy crédible\n5. Résume en un \"Total de valeur délivrée\" ce trimestre", tags: ['valeur', 'métriques', 'ROI'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'qbr-005', category: 'qbr', title: 'Plan de redressement post-QBR difficile', description: "Votre QBR s'est mal passée ? Voici comment rebondir.", prompt: "Tu es un KAM senior qui a géré des situations de crise. Ma dernière QBR s'est mal passée.\n\nCe qui s'est passé : [RÉSUMÉ]\nRéactions du client : [RÉSUMÉ]\nNiveau de risque actuel : [1-10]\n\nCrée un plan de redressement :\n1. Actions dans les 48h (damage control)\n2. Communication interne (escalade, support nécessaire)\n3. Plan de reconquête sur 30 jours\n4. Métriques de suivi pour mesurer le redressement\n5. Script d'email de suivi post-QBR difficile", tags: ['crise', 'redressement', 'suivi'], difficulty: 'advanced', gordonBoost: true },
  { id: 'qbr-006', category: 'qbr', title: 'Transformer la QBR en opportunité de vente', description: "Utilisez la QBR comme levier d'expansion commerciale.", prompt: "Tu es un expert en account expansion. Aide-moi à intégrer subtilement des opportunités de vente dans ma prochaine QBR.\n\nCompte : [NOM]\nProduits/services actuels : [LISTE]\nProduits à proposer : [LISTE]\n\nConseille-moi :\n1. À quel moment de la QBR introduire les opportunités\n2. Comment les lier aux résultats du trimestre (\"puisque X a fonctionné, Y pourrait...\")\n3. Le wording exact pour ne pas paraître \"pushy\"\n4. Comment obtenir un next step concret (pas juste \"on va y réfléchir\")\n5. Le piège à éviter absolument en QBR-vente", tags: ['expansion', 'vente', 'opportunité'], difficulty: 'advanced', gordonBoost: true },
  { id: 'qbr-007', category: 'qbr', title: 'Template email post-QBR', description: "Envoyez un compte-rendu professionnel après votre QBR.", prompt: "Tu es un KAM organisé. Rédige un email de suivi post-QBR.\n\nCompte : [NOM]\nDate de la QBR : [DATE]\nParticipants : [LISTE]\nDécisions prises : [LISTE]\nActions convenues : [LISTE AVEC RESPONSABLES]\n\nL'email doit :\n1. Remercier les participants\n2. Résumer les points clés en bullet points\n3. Lister les actions avec responsable + deadline\n4. Confirmer la prochaine QBR\n5. Finir sur une note positive et engageante\n\nTon : professionnel, concis, actionnable.", tags: ['email', 'suivi', 'compte-rendu'], difficulty: 'starter', gordonBoost: false },
  { id: 'qbr-008', category: 'qbr', title: 'QBR pour un nouveau compte', description: "Structurez votre première QBR avec un nouveau client.", prompt: "Tu es un consultant KAM. C'est ma première QBR avec ce client. Il n'y a pas d'historique.\n\nCompte : [NOM]\nDurée de la relation : [MOIS]\nOnboarding terminé : [OUI/NON]\n\nAide-moi à :\n1. Structurer une QBR de \"fondation\" (vs une QBR de routine)\n2. Les questions à poser pour établir la baseline\n3. Comment définir les KPIs pour les prochains trimestres ensemble\n4. Éviter l'erreur de \"trop promettre\" en première QBR\n5. Comment terminer sur un engagement mutuel fort", tags: ['premier', 'onboarding', 'fondation'], difficulty: 'intermediate', gordonBoost: false },

  // CAPTURE PLAN (8)
  { id: 'cp-001', category: 'capture-plan', title: 'Capture Plan stratégique', description: 'Créez un plan de rétention proactif pour sécuriser un renouvellement.', prompt: "Tu es un expert en rétention stratégique. Aide-moi à construire un Capture Plan.\n\nCompte : [NOM]\nCA annuel : [MONTANT]\nDate de renouvellement : [DATE]\nDurée avant renouvellement : [MOIS]\n\nCrée un Capture Plan complet :\n1. Stakeholder map (qui décide, qui influence)\n2. Évaluation des risques (compétitifs, internes, budgétaires)\n3. Proposition de valeur à renforcer\n4. Timeline d'actions (J-180, J-120, J-90, J-60, J-30)\n5. Stratégie de communication par stakeholder\n6. Plan B si le renouvellement est menacé", tags: ['rétention', 'renouvellement', 'capture'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'cp-002', category: 'capture-plan', title: 'Défendre contre un concurrent entrant', description: 'Votre client évalue un concurrent ? Préparez votre stratégie défensive.', prompt: "Tu es un stratège commercial aguerri. Mon client évalue un concurrent pour me remplacer.\n\nCompte : [NOM]\nConcurrent : [NOM]\nRaison de l'évaluation : [PRIX / FONCTIONNALITÉS / POLITIQUE INTERNE / AUTRE]\nTimeline de décision : [DATE]\n\nFournis :\n1. Analyse des motivations réelles du client\n2. Points forts/faibles du concurrent vs nous\n3. Stratégie de défense (3 scénarios)\n4. Argumentaire \"coût du changement\" (switching cost)\n5. Actions immédiates (cette semaine)\n6. Script pour la prochaine réunion avec le client", tags: ['défense', 'concurrent', 'rétention'], difficulty: 'advanced', gordonBoost: true },
  { id: 'cp-003', category: 'capture-plan', title: "Préparer l'argumentaire de renouvellement", description: "Construisez un business case solide pour justifier le renouvellement.", prompt: "Tu es un expert en value selling B2B. Aide-moi à préparer mon argumentaire de renouvellement.\n\nCompte : [NOM]\nPrix actuel : [MONTANT]\nValeur délivrée cette année : [RÉSUMÉ]\nDemande du client : [REMISE / MÊME PRIX / HAUSSE ACCEPTÉE]\n\nGénère :\n1. Business case chiffré (ROI, TCO, valeur délivrée vs investissement)\n2. 5 arguments clés, classés par impact\n3. Réponse à l'objection prix\n4. Comparaison \"avec nous vs sans nous\" (scénario de non-renouvellement)\n5. Offre de renouvellement recommandée (structure)", tags: ['renouvellement', 'prix', 'business case'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'cp-004', category: 'capture-plan', title: 'Gérer un changement de sponsor', description: 'Votre sponsor interne quitte le client. Comment sécuriser la relation ?', prompt: "Tu es un KAM senior. Mon sponsor principal chez le client part (promotion, démission, réorg).\n\nCompte : [NOM]\nSponsor sortant : [NOM, RÔLE]\nRemplaçant potentiel : [NOM, RÔLE si connu]\n\nConseille-moi :\n1. Actions immédiates (avant le départ)\n2. Comment obtenir une introduction au remplaçant\n3. Comment re-vendre la valeur à un nouveau décideur\n4. Pièges à éviter dans la transition\n5. Script d'email au sponsor sortant (demande de recommandation)\n6. Script d'email au nouveau contact (introduction)", tags: ['sponsor', 'transition', 'relation'], difficulty: 'advanced', gordonBoost: true },
  { id: 'cp-005', category: 'capture-plan', title: 'Négocier une hausse de prix', description: 'Préparez et communiquez une augmentation tarifaire à un grand compte.', prompt: "Tu es un expert en négociation B2B. Je dois annoncer une hausse de prix à un compte stratégique.\n\nCompte : [NOM]\nHausse prévue : [%]\nRaison : [INFLATION / VALEUR AJOUTÉE / ALIGNEMENT MARCHÉ]\nRelation actuelle : [BONNE / TENDUE / NEUTRE]\n\nGénère :\n1. Timing optimal pour l'annonce\n2. Structure de l'argumentaire (justification + valeur)\n3. Script de la conversation\n4. Réponses aux 5 objections les plus probables\n5. Concessions possibles (sans baisser le prix)\n6. Plan B si le client refuse catégoriquement", tags: ['prix', 'négociation', 'hausse'], difficulty: 'advanced', gordonBoost: true },
  { id: 'cp-006', category: 'capture-plan', title: 'Identifier les champions internes', description: 'Repérez et activez vos alliés chez le client pour sécuriser le compte.', prompt: "Tu es un expert en vente complexe. Aide-moi à identifier et activer des champions internes chez mon client.\n\nCompte : [NOM]\nContacts actuels : [LISTE AVEC RÔLES]\nHistorique de la relation : [RÉSUMÉ]\n\nFournis :\n1. Critères pour identifier un vrai champion (vs un faux allié)\n2. Questions à poser pour tester l'engagement de chaque contact\n3. Comment transformer un utilisateur satisfait en champion actif\n4. Plan de mobilisation des champions avant le renouvellement\n5. Comment récompenser/valoriser vos champions sans franchir la ligne éthique", tags: ['champion', 'interne', 'mobilisation'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'cp-007', category: 'capture-plan', title: "Early warning system pour le churn", description: 'Mettez en place un système de détection précoce des risques.', prompt: "Tu es un expert en Customer Success et KAM. Aide-moi à créer un système d'alerte précoce pour détecter les risques de churn.\n\nType de comptes : [SECTEUR / TAILLE]\nOutils CRM utilisés : [LISTE]\n\nCrée :\n1. Liste des 15 signaux faibles de churn (comportementaux, relationnels, contractuels)\n2. Scoring de risque : comment pondérer chaque signal\n3. Seuils d'alerte (vert / orange / rouge)\n4. Actions automatiques par niveau d'alerte\n5. Dashboard de suivi recommandé (métriques clés)", tags: ['churn', 'alerte', 'prévention'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'cp-008', category: 'capture-plan', title: 'Reconquérir un compte perdu', description: "Stratégie pour récupérer un client qui vous a quitté.", prompt: "Tu es un expert en win-back B2B. Un de mes comptes stratégiques nous a quittés il y a [DURÉE].\n\nCompte : [NOM]\nRaison du départ : [RÉSUMÉ]\nConcurrent choisi : [NOM]\nCA perdu : [MONTANT]\n\nCrée une stratégie de reconquête :\n1. Timing optimal pour reprendre contact\n2. Angle d'approche (ce qui a changé chez nous)\n3. Recherche d'intelligence : comment savoir si le concurrent déçoit\n4. Script de reprise de contact (email + téléphone)\n5. Offre de reconquête recommandée\n6. Timeline sur 6 mois", tags: ['reconquête', 'win-back', 'stratégie'], difficulty: 'advanced', gordonBoost: true },

  // OBJECTIONS (9)
  { id: 'obj-001', category: 'objections', title: "Traiter l'objection prix en grand compte", description: "Répondez avec assurance quand un décideur challenge votre prix.", prompt: "Tu es un expert en négociation grands comptes. Mon client dit : \"Vous êtes trop cher.\"\n\nContexte : [DESCRIPTION DE LA SITUATION]\nPrix proposé : [MONTANT]\nConcurrent moins cher : [OUI/NON, NOM si connu]\n\nFournis :\n1. Les 3 techniques de réponse les plus efficaces en B2B\n2. Comment reframer le débat prix → valeur\n3. Questions à poser pour comprendre la vraie objection derrière le prix\n4. Script de réponse (mot pour mot)\n5. Ce qu'il ne faut JAMAIS dire face à cette objection", tags: ['prix', 'négociation', 'objection'], difficulty: 'starter', gordonBoost: true },
  { id: 'obj-002', category: 'objections', title: "\"On va lancer un appel d'offres\"", description: "Votre client veut vous mettre en compétition. Comment réagir ?", prompt: "Tu es un stratège commercial B2B. Mon client annonce un appel d'offres pour le renouvellement.\n\nCompte : [NOM]\nMotivation probable : [POLITIQUE INTERNE / PRIX / RÉEL BESOIN DE CHANGEMENT]\n\nConseille-moi :\n1. Comment réagir dans la réunion (attitude, mots)\n2. Les 3 questions à poser immédiatement\n3. Comment influencer le cahier des charges en votre faveur\n4. Stratégie si l'AO est inévitable vs si on peut l'éviter\n5. Comment mobiliser vos champions internes pendant l'AO", tags: ['appel offres', 'compétition', 'stratégie'], difficulty: 'advanced', gordonBoost: true },
  { id: 'obj-003', category: 'objections', title: "\"Je dois en parler à mon manager\"", description: "L'interlocuteur n'a pas le pouvoir de décision. Comment avancer ?", prompt: "Tu es un coach en vente complexe. Mon contact dit : \"Je dois en parler à mon manager / au comité.\"\n\nContexte : [DESCRIPTION]\nCe que vous vendez : [RÉSUMÉ]\n\nFournis :\n1. Comment évaluer si c'est une vraie objection ou un brush-off\n2. Comment armer votre champion pour vendre en interne\n3. Le document/email que votre contact peut forward à son manager\n4. Comment proposer une réunion avec le décideur sans court-circuiter\n5. Script de réponse immédiate", tags: ['décideur', 'champion', 'escalade'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'obj-004', category: 'objections', title: "\"On est satisfait de notre solution actuelle\"", description: "Le client ne voit pas la raison de changer. Comment créer le doute ?", prompt: "Tu es un expert en consultative selling. Mon prospect dit : \"On est satisfait de notre fournisseur actuel.\"\n\nLeur fournisseur : [NOM si connu]\n\nFournis :\n1. Pourquoi cette objection est en réalité une opportunité\n2. Les 5 questions qui créent le doute sans être agressif\n3. Comment introduire le concept de \"coût de l'inaction\"\n4. Exemples de transitions qui ont fonctionné dans des cas similaires\n5. La stratégie du \"gardez votre solution, ajoutez la nôtre\" (land and expand)", tags: ['statu quo', 'changement', 'prospection'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'obj-005', category: 'objections', title: "\"Le timing n'est pas bon\"", description: "Le client repousse la décision. Comment créer l'urgence ?", prompt: "Tu es un expert en closing B2B. Mon client dit : \"Pas maintenant, revenez dans 6 mois.\"\n\nContexte : [DESCRIPTION]\nRaison invoquée : [BUDGET / RÉORG / PRIORITÉS]\n\nFournis :\n1. Comment distinguer un vrai problème de timing d'un non dit\n2. Techniques pour créer l'urgence sans être pushy\n3. Comment rester top-of-mind pendant l'attente\n4. Le calendrier de suivi optimal (fréquence, canal, contenu)\n5. Offre de \"pré-engagement\" pour sécuriser le deal future", tags: ['timing', 'urgence', 'suivi'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'obj-006', category: 'objections', title: "Traiter les objections du Procurement", description: "Les Achats ont leurs propres tactiques. Préparez-vous.", prompt: "Tu es un expert en négociation avec les services Achats B2B. Je vais rencontrer le Procurement de mon client.\n\nCompte : [NOM]\nMontant du deal : [MONTANT]\nTactiques probables du Procurement : [REMISE DEMANDÉE / MISE EN CONCURRENCE / ALLONGEMENT PAIEMENT]\n\nPrépare-moi :\n1. Les 7 tactiques classiques des Achats et comment y répondre\n2. Comment défendre le prix sans perdre la relation\n3. Les concessions non-prix à proposer (scope, timeline, services)\n4. Le moment où il faut escalader vers le business owner\n5. Red flags qui indiquent que le deal est en danger", tags: ['achats', 'procurement', 'négociation'], difficulty: 'advanced', gordonBoost: true },
  { id: 'obj-007', category: 'objections', title: "\"Votre concurrent offre plus de fonctionnalités\"", description: "Le client compare feature par feature. Comment reframer ?", prompt: "Tu es un expert en positionnement compétitif. Mon client dit : \"Votre concurrent [NOM] offre X, Y, Z que vous n'avez pas.\"\n\nFonctionnalités manquantes citées : [LISTE]\n\nFournis :\n1. Comment reframer le débat features → résultats business\n2. Argumentaire : \"Pourquoi moins de features peut être un avantage\"\n3. Questions à poser pour comprendre le vrai besoin derrière la feature\n4. Technique de la \"future roadmap\" (sans promettre)\n5. Quand concéder et quand défendre sa position", tags: ['fonctionnalités', 'concurrence', 'positionnement'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'obj-008', category: 'objections', title: "\"On n'a pas le budget\"", description: "L'objection budget la plus classique. Comment la dépasser ?", prompt: "Tu es un expert en justification de budget B2B. Mon client dit : \"On n'a pas le budget cette année.\"\n\nMontant de notre solution : [MONTANT]\nBudget du client pour ce type de solution : [CONNU/INCONNU]\n\nFournis :\n1. 4 techniques pour \"trouver\" du budget chez le client\n2. Comment construire un business case qui convainc le CFO\n3. Les alternatives de structuration (étalement, paiement différé, phase 1 réduite)\n4. Questions qui révèlent si le budget est un vrai obstacle ou un prétexte\n5. Template d'email de justification de budget pour votre champion", tags: ['budget', 'ROI', 'justification'], difficulty: 'starter', gordonBoost: true },
  { id: 'obj-009', category: 'objections', title: "\"On va développer ça en interne\"", description: "Le client veut construire plutôt qu'acheter. Comment répondre ?", prompt: "Tu es un expert en vente de solutions vs build. Mon client dit : \"On préfère développer ça en interne.\"\n\nCe que nous vendons : [DESCRIPTION]\nCapacités internes du client : [RÉSUMÉ]\n\nFournis :\n1. L'analyse Buy vs Build complète (coûts cachés du build)\n2. Les 5 arguments les plus percutants pour le Buy\n3. Comment quantifier le coût d'opportunité du développement interne\n4. Cas d'étude type : \"Ils ont essayé en interne et sont revenus vers nous\"\n5. Le compromis intelligent : \"Construisez X, achetez Y\" (stratégie de coexistence)", tags: ['build vs buy', 'interne', 'ROI'], difficulty: 'intermediate', gordonBoost: false },

  // RELATIONSHIP MAPPING (8)
  { id: 'rm-001', category: 'relationship-mapping', title: 'Cartographier les décideurs', description: "Identifiez qui décide vraiment chez votre client.", prompt: "Tu es un expert en vente complexe B2B. Aide-moi à cartographier les décideurs de ce compte.\n\nCompte : [NOM]\nType de décision : [ACHAT INITIAL / RENOUVELLEMENT / EXPANSION]\nBudget estimé : [MONTANT]\n\nPour chaque rôle type (Sponsor Exécutif, Décideur Technique, Utilisateur Final, Acheteur, Influenceur), fournis :\n1. Titre probable dans l'organigramme\n2. Critères de décision spécifiques\n3. Objections probables\n4. Message clé adapté\n5. Niveau d'engagement nécessaire (faible/moyen/fort)", tags: ['décideurs', 'cartographie', 'rôles'], difficulty: 'starter', gordonBoost: false },
  { id: 'rm-002', category: 'relationship-mapping', title: 'Identifier les bloqueurs', description: "Repérez les résistances internes chez le client.", prompt: "Tu es un stratège de vente complexe. Aide-moi à identifier et gérer les bloqueurs potentiels.\n\nCompte : [NOM]\nProjet/deal en cours : [DESCRIPTION]\nBloqueurs suspectés : [NOMS/RÔLES si connus]\n\nFournis :\n1. Les 5 profils types de bloqueurs en vente B2B\n2. Signaux qui indiquent qu'un contact est un bloqueur\n3. Stratégies pour chaque profil de bloqueur\n4. Comment neutraliser un bloqueur sans conflit\n5. Quand ignorer un bloqueur vs quand le confronter", tags: ['bloqueur', 'résistance', 'politique'], difficulty: 'advanced', gordonBoost: true },
  { id: 'rm-003', category: 'relationship-mapping', title: 'Stratégie multi-thread', description: "Développez des contacts à plusieurs niveaux hiérarchiques.", prompt: "Tu es un expert en account management stratégique. Je n'ai qu'un seul contact chez ce client. C'est risqué.\n\nCompte : [NOM]\nContact unique : [NOM, RÔLE]\nNiveaux à couvrir : [OPÉRATIONNEL / MANAGEMENT / DIRECTION]\n\nCrée un plan de multi-threading :\n1. Pourquoi un seul contact est le plus grand risque en KAM\n2. Stratégie pour obtenir des introductions sans court-circuiter\n3. Événements/prétextes pour rencontrer d'autres niveaux\n4. Template d'email pour demander une introduction\n5. Objectif de couverture à 90 jours (nombre de contacts par niveau)", tags: ['multi-thread', 'contacts', 'risque'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'rm-004', category: 'relationship-mapping', title: 'Comprendre la politique interne', description: "Décryptez les dynamiques de pouvoir chez votre client.", prompt: "Tu es un conseiller en vente politique B2B. Aide-moi à comprendre la politique interne de ce compte.\n\nCompte : [NOM]\nÉvénements récents : [RÉORG / FUSION / NOUVEAU CEO / AUTRE]\nTensions observées : [ENTRE QUI ET QUI]\n\nAnalyse :\n1. Comment ces changements impactent notre position\n2. Les gagnants et perdants de la situation\n3. Où nous positionner dans ce nouveau paysage\n4. Les alliances à former et celles à éviter\n5. Le piège politique n°1 à éviter en KAM", tags: ['politique', 'pouvoir', 'dynamiques'], difficulty: 'advanced', gordonBoost: false },
  { id: 'rm-005', category: 'relationship-mapping', title: 'Construire une relation C-level', description: "Accédez et maintenez une relation avec les dirigeants.", prompt: "Tu es un expert en executive selling. Je veux construire une relation avec le C-level de mon client.\n\nCompte : [NOM]\nCible C-level : [TITRE : CEO, CFO, CTO, COO...]\nRelation actuelle : [AUCUNE / DISTANTE / CORRECTE]\n\nConseille-moi :\n1. Les 3 canaux pour accéder au C-level (LinkedIn, événement, introduction)\n2. Ce qui intéresse un C-level (vs un manager opérationnel)\n3. Comment apporter de la valeur AVANT de demander quoi que ce soit\n4. La fréquence de contact idéale avec un C-level\n5. Le format de communication préféré des dirigeants\n6. Les erreurs fatales qui vous font perdre l'accès C-level", tags: ['C-level', 'exécutif', 'relation'], difficulty: 'advanced', gordonBoost: true },
  { id: 'rm-006', category: 'relationship-mapping', title: 'Préparer un événement client', description: "Planifiez un événement stratégique pour renforcer les relations.", prompt: "Tu es un expert en relation client B2B. Je veux organiser un événement pour mes contacts clés chez ce compte.\n\nCompte : [NOM]\nNombre de contacts à inviter : [N]\nBudget : [MONTANT]\nObjectif : [RENFORCER / ÉTENDRE / CÉLÉBRER]\n\nPropose :\n1. 3 formats d'événements adaptés au contexte\n2. Le programme idéal (timing, contenu, networking)\n3. Comment sélectionner les bons invités\n4. Les messages clés à passer pendant l'événement\n5. Le suivi post-événement (dans les 48h)", tags: ['événement', 'networking', 'relation'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'rm-007', category: 'relationship-mapping', title: 'Plan de contacts trimestriel', description: "Structurez vos interactions avec tous les niveaux du compte.", prompt: "Tu es un KAM méthodique. Crée un plan de contacts trimestriel pour ce compte.\n\nCompte : [NOM]\nContacts actuels : [LISTE AVEC NOM, RÔLE, NIVEAU]\nFréquence actuelle : [RÉSUMÉ]\n\nGénère un plan :\n1. Tableau : Contact / Fréquence / Format / Objectif\n2. Événements clés du trimestre (QBR, anniversaire contrat, etc.)\n3. Contenu à partager par niveau (C-level: insights marché, Ops: best practices, Tech: roadmap)\n4. Métriques de suivi (NPS, sentiment, engagement)\n5. Actions de \"surprise and delight\" (petites attentions à impact)", tags: ['plan', 'contacts', 'trimestre'], difficulty: 'starter', gordonBoost: false },
  { id: 'rm-008', category: 'relationship-mapping', title: 'Gérer la relation en période de crise', description: "Maintenez la confiance quand les choses vont mal.", prompt: "Tu es un expert en gestion de crise B2B. Nous avons un incident majeur avec ce client.\n\nCompte : [NOM]\nIncident : [DESCRIPTION]\nImpact client : [DESCRIPTION]\nRéaction du client : [COLÈRE / DÉCEPTION / MENACE]\n\nConseille-moi :\n1. Les 5 règles d'or de la communication de crise en KAM\n2. Script d'appel d'urgence (dans l'heure)\n3. Email de suivi (dans les 4h)\n4. Plan de résolution avec timeline transparente\n5. Comment transformer cette crise en renforcement de la relation", tags: ['crise', 'incident', 'confiance'], difficulty: 'advanced', gordonBoost: true },

  // SCORING (8)
  { id: 'sc-001', category: 'scoring', title: 'Scoring de potentiel client', description: 'Évaluez le potentiel stratégique de vos comptes.', prompt: "Tu es un analyste KAM. Aide-moi à scorer le potentiel de ce compte sur 6 dimensions.\n\nCompte : [NOM]\nSecteur : [SECTEUR]\nCA actuel : [MONTANT]\nTaille entreprise : [EFFECTIF]\n\nScore chaque dimension de 1 à 5 et justifie :\n1. Potentiel de revenu (taille du wallet)\n2. Fit stratégique (alignement avec notre offre)\n3. Force de la relation (accès, confiance)\n4. Probabilité de croissance (tendance du compte)\n5. Position concurrentielle (notre avantage)\n6. Timeline de décision (urgence/prochaines étapes)\n\nScore total /30 + recommandation (Invest / Maintain / Divest)", tags: ['scoring', 'potentiel', 'priorisation'], difficulty: 'starter', gordonBoost: false },
  { id: 'sc-002', category: 'scoring', title: 'Segmenter son portefeuille', description: 'Classez vos comptes en tiers stratégiques.', prompt: "Tu es un consultant en stratégie commerciale. Aide-moi à segmenter mon portefeuille de comptes.\n\nNombre de comptes : [N]\nCA total : [MONTANT]\nRépartition actuelle du temps : [RÉSUMÉ]\n\nFournis :\n1. Critères de segmentation recommandés (Pareto, stratégique, potentiel)\n2. Définition de chaque tier : Platinum / Gold / Silver / Bronze\n3. Allocation de temps recommandée par tier\n4. Actions types par tier (fréquence de contact, type de QBR, investissement)\n5. Comment communiquer la segmentation en interne (à son manager)", tags: ['segmentation', 'portefeuille', 'tiers'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'sc-003', category: 'scoring', title: 'Analyse Pareto du portefeuille', description: 'Appliquez la règle 80/20 à votre portefeuille.', prompt: "Tu es un analyste commercial. Aide-moi à appliquer le principe de Pareto à mon portefeuille.\n\nNombre total de comptes : [N]\nListe des comptes avec CA : [FORMAT : Nom — CA]\n\nAnalyse :\n1. Identification des 20% qui font 80% du CA\n2. Identification des comptes à fort potentiel sous-investis\n3. Identification des comptes chronophages à faible CA\n4. Recommandation de réallocation du temps\n5. Actions concrètes : quels comptes intensifier, quels comptes déléguer", tags: ['Pareto', '80/20', 'réallocation'], difficulty: 'starter', gordonBoost: false },
  { id: 'sc-004', category: 'scoring', title: 'Scoring de risque par compte', description: "Identifiez les comptes les plus à risque dans votre portefeuille.", prompt: "Tu es un expert en risk management commercial. Aide-moi à scorer le risque de mes comptes.\n\nListe de comptes : [FORMAT : Nom — CA — Date renouvellement — Commentaire]\n\nPour chaque compte, évalue le risque (1-10) sur :\n1. Risque contractuel (date renouvellement, clauses)\n2. Risque relationnel (dépendance à un contact, turnover)\n3. Risque concurrentiel (agressivité des concurrents)\n4. Risque de satisfaction (incidents, NPS, feedback)\n5. Risque économique (santé financière du client)\n\nClassement final par risque global + top 3 actions de mitigation", tags: ['risque', 'scoring', 'mitigation'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'sc-005', category: 'scoring', title: "Matrice d'attractivité vs position", description: "Positionnez vos comptes sur la matrice stratégique classique.", prompt: "Tu es un stratège commercial. Aide-moi à construire une matrice Attractivité du client vs Force de notre position.\n\nComptes à positionner : [LISTE AVEC CA ET COMMENTAIRE]\n\nPour chaque compte :\n1. Score d'attractivité (1-10) : taille, croissance, marge, prestige\n2. Score de position (1-10) : part de wallet, relation, avantage concurrentiel\n3. Positionnement dans la matrice 2x2\n4. Stratégie par quadrant :\n   - Haute attractivité + Forte position → Investir\n   - Haute attractivité + Faible position → Développer\n   - Faible attractivité + Forte position → Défendre/Rentabiliser\n   - Faible attractivité + Faible position → Désengager", tags: ['matrice', 'stratégie', 'attractivité'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'sc-006', category: 'scoring', title: "Calculer le Customer Lifetime Value", description: "Estimez la valeur à vie de vos comptes stratégiques.", prompt: "Tu es un analyste financier commercial. Aide-moi à calculer le CLV de mes comptes clés.\n\nCompte : [NOM]\nCA annuel actuel : [MONTANT]\nMarge brute : [%]\nDurée moyenne de la relation dans le secteur : [ANNÉES]\nTaux de croissance annuel estimé : [%]\nCoût de service annuel : [MONTANT]\n\nCalcule :\n1. CLV simple (CA × marge × durée)\n2. CLV avec croissance (intégrant le taux de croissance)\n3. CLV net (après coût de service)\n4. Comparaison avec le coût d'acquisition\n5. Recommandation d'investissement basée sur le CLV", tags: ['CLV', 'valeur', 'financier'], difficulty: 'advanced', gordonBoost: false },
  { id: 'sc-007', category: 'scoring', title: 'Prioriser les actions de la semaine', description: "Décidez où investir votre temps cette semaine.", prompt: "Tu es un coach de productivité KAM. Aide-moi à prioriser mes actions cette semaine.\n\nMes comptes et situations :\n[FORMAT PAR COMPTE : Nom — CA — Situation actuelle — Action envisagée]\n\nEn utilisant la matrice Urgence/Impact, classe chaque action dans :\n1. Faire immédiatement (urgent + fort impact)\n2. Planifier (non urgent + fort impact)\n3. Déléguer (urgent + faible impact)\n4. Éliminer (non urgent + faible impact)\n\nPropose un planning semaine (lundi à vendredi) avec les créneaux alloués.", tags: ['priorité', 'semaine', 'productivité'], difficulty: 'starter', gordonBoost: false },
  { id: 'sc-008', category: 'scoring', title: 'Benchmark interne des comptes', description: "Comparez vos comptes entre eux pour identifier les best practices.", prompt: "Tu es un consultant en performance commerciale. Aide-moi à benchmarker mes comptes.\n\nComptes à comparer : [FORMAT : Nom — CA — Marge — Ancienneté — NPS]\n\nFournis :\n1. Tableau comparatif sur 6 métriques\n2. Identification du \"compte modèle\" (best-in-class)\n3. Ce qui rend ce compte modèle différent\n4. Actions pour répliquer ce succès sur les autres comptes\n5. Les 3 quick wins les plus impactants", tags: ['benchmark', 'comparaison', 'best practice'], difficulty: 'intermediate', gordonBoost: false },
]

const promptsEN: Prompt[] = [
  // ACCOUNT ANALYSIS (9)
  { id: 'aa-001', category: 'account-analysis', title: '360° Account Analysis', description: 'Get a comprehensive view of your strategic account in minutes.', prompt: 'You are a KAM expert. Analyze this strategic account comprehensively.\n\nAccount: [ACCOUNT NAME]\nIndustry: [INDUSTRY]\nCurrent revenue: [AMOUNT]\nRelationship tenure: [DURATION]\n\nProvide:\n1. Strengths of the current relationship\n2. Identified weaknesses\n3. Growth opportunities\n4. Threats (competition, budget, reorganization)\n5. Account health score (1-10)\n6. 3 priority actions for the next 30 days', tags: ['SWOT', 'analysis', 'strategy'], difficulty: 'starter', gordonBoost: true },
  { id: 'aa-002', category: 'account-analysis', title: 'Identify Untapped Potential', description: 'Discover hidden expansion opportunities within your existing accounts.', prompt: "You are a KAM expert specializing in account expansion.\n\nAccount: [NAME]\nProducts/services currently sold: [LIST]\nDepartments covered: [LIST]\nCurrent revenue: [AMOUNT]\n\nAnalyze:\n1. Which departments are not yet using our solutions?\n2. What complementary products/services could be offered?\n3. Are there subsidiaries or entities not yet addressed?\n4. Estimate growth potential in % and value\n5. Propose a 3-step penetration strategy", tags: ['expansion', 'upsell', 'cross-sell'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'aa-003', category: 'account-analysis', title: 'Competitive Analysis on the Account', description: "Assess your competitors' position at your client.", prompt: "You are a KAM strategist. Analyze the competitive position on this account.\n\nAccount: [NAME]\nIdentified competitors at the client: [LIST]\nOur estimated market share: [%]\n\nProvide:\n1. Comparison matrix (us vs each competitor) on 5 criteria\n2. Vulnerability points of each competitor\n3. Our differentiating competitive advantage\n4. Displacement risk (1-10)\n5. Recommended defensive strategy\n6. Offensive strategy to gain market share", tags: ['competition', 'defensive', 'offensive'], difficulty: 'advanced', gordonBoost: false },
  { id: 'aa-004', category: 'account-analysis', title: 'Understand the Decision-Making Structure', description: "Decode your account's decision-making structure.", prompt: "You are a complex B2B sales expert. Help me understand the decision-making structure of this account.\n\nAccount: [NAME]\nIndustry: [INDUSTRY]\nSize: [HEADCOUNT]\nPurchase type: [NEW / RENEWAL / EXPANSION]\n\nDescribe:\n1. Typical roles involved in this type of decision\n2. Likely decision process (steps, timeline)\n3. Decision criteria by role (technical, financial, strategic)\n4. How to identify the real decision-maker vs the signatory\n5. Questions to ask to map the decision circuit", tags: ['decision', 'org chart', 'complex sale'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'aa-005', category: 'account-analysis', title: 'Client Relationship Audit', description: 'Assess the quality and depth of your relationship.', prompt: "You are a senior KAM consultant. Help me audit the quality of my relationship with this account.\n\nAccount: [NAME]\nContact frequency: [WEEKLY/MONTHLY/QUARTERLY]\nNumber of active contacts: [N]\nHierarchical levels covered: [OPERATIONAL/MANAGEMENT/EXECUTIVE]\n\nAssess:\n1. Relationship depth score (1-10) with justification\n2. Identified gaps (uncovered levels, missing departments)\n3. Single-contact dependency risk\n4. Action plan to broaden and deepen the relationship\n5. Recommended contact frequency by level", tags: ['relationship', 'audit', 'contacts'], difficulty: 'starter', gordonBoost: false },
  { id: 'aa-006', category: 'account-analysis', title: "Analyze the Client's Business Challenges", description: "Understand your client's strategic priorities to better position yourself.", prompt: "You are a B2B business analyst. Help me understand my client's strategic challenges.\n\nClient: [NAME]\nIndustry: [INDUSTRY]\nLatest known news: [SUMMARY]\n\nAnalyze:\n1. The 3 likely strategic priorities of this client\n2. External pressures (regulation, competition, market)\n3. Likely internal challenges (transformation, cost reduction, growth)\n4. How our solution aligns with these challenges\n5. How to reframe our value proposition in the client's language", tags: ['strategy', 'business', 'value'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'aa-007', category: 'account-analysis', title: 'Churn Risk Analysis', description: 'Identify warning signals before losing an account.', prompt: "You are an expert in strategic account retention. Help me assess the churn risk.\n\nAccount: [NAME]\nAnnual revenue: [AMOUNT]\nRenewal date: [DATE]\nObserved signals: [LIST: e.g., fewer meetings, benchmark requests, sponsor change...]\n\nProvide:\n1. Churn risk score (1-10) with justification\n2. Signal classification (red / amber / green)\n3. Likely root causes\n4. Emergency retention plan (actions D+7, D+30, D+60)\n5. Value argument to prepare for the next meeting", tags: ['churn', 'retention', 'risk'], difficulty: 'advanced', gordonBoost: true },
  { id: 'aa-008', category: 'account-analysis', title: 'Prepare an Account Executive Summary', description: 'Create an executive summary for your leadership or the client.', prompt: "You are a senior KAM presenting an account to leadership. Generate an executive summary.\n\nAccount: [NAME]\nRevenue: [AMOUNT]\nProducts: [LIST]\nHistory: [2-3 LINE SUMMARY]\n\nStructure the summary as:\n1. Overview (2 sentences max)\n2. Key metrics (revenue, margin, satisfaction, tenure)\n3. Key highlights from last quarter\n4. Risks and opportunities\n5. Strategic recommendation\n6. Next steps\n\nTone: professional, concise, decision-oriented.", tags: ['executive', 'summary', 'leadership'], difficulty: 'starter', gordonBoost: false },
  { id: 'aa-009', category: 'account-analysis', title: "Map the Client's Value Chain", description: "Understand how your client creates value to better position yourself.", prompt: "You are a B2B strategy consultant. Help me map my client's value chain.\n\nClient: [NAME]\nIndustry: [INDUSTRY]\nCore business: [DESCRIPTION]\n\nDescribe:\n1. Key steps in the client's value chain\n2. Where we currently contribute\n3. Where we could contribute (unaddressed areas)\n4. The impact of our solution on their value chain\n5. How to quantify this impact in business terms (ROI, TCO, productivity)", tags: ['value chain', 'positioning', 'ROI'], difficulty: 'advanced', gordonBoost: false },

  // QBR (8)
  { id: 'qbr-001', category: 'qbr', title: 'Complete QBR Structure', description: 'Generate a professional QBR plan in minutes.', prompt: "You are an expert in strategic account reviews. Help me structure my next QBR.\n\nAccount: [NAME]\nClient-side participants: [NAMES AND ROLES]\nMain objective: [RETENTION / EXPANSION / TURNAROUND]\n\nGenerate a complete QBR plan:\n1. Opening slide (agenda + objectives)\n2. Quarter review (results vs targets)\n3. Value delivered (impact metrics)\n4. Incidents and resolutions\n5. Strategic vision (next 90 days)\n6. Identified opportunities\n7. Joint action plan\n8. Next steps\n\nFor each section, provide key content and discussion points.", tags: ['QBR', 'structure', 'quarterly'], difficulty: 'starter', gordonBoost: true },
  { id: 'qbr-002', category: 'qbr', title: 'Prepare for Tough QBR Questions', description: 'Anticipate the questions your client will ask and prepare your answers.', prompt: "You are an experienced KAM coach. My client will ask tough questions at my next QBR.\n\nContext: [SITUATION SUMMARY]\nKnown pain points: [LIST]\n\nGenerate:\n1. The 10 most likely client questions\n2. For each question: a structured response (acknowledge → explain → action)\n3. Traps to avoid\n4. How to turn criticism into opportunity\n5. Transition phrases to maintain control of the discussion", tags: ['QBR', 'objections', 'preparation'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'qbr-003', category: 'qbr', title: 'QBR Opening Script', description: 'Start your QBR with impact and credibility.', prompt: "You are an executive communication expert. Write a QBR opening script.\n\nAccount: [NAME]\nMost senior client participant: [NAME, TITLE]\nRelationship tone: [EXCELLENT / GOOD / TENSE / NEW]\n\nThe script must:\n1. Last 2-3 minutes max\n2. Thank and contextualize\n3. Recall shared objectives\n4. Announce the agenda with client benefits\n5. Create engagement from the start\n\nAdapt the tone to the relationship level.", tags: ['QBR', 'script', 'opening'], difficulty: 'starter', gordonBoost: false },
  { id: 'qbr-004', category: 'qbr', title: 'Quantify Value Delivered', description: 'Turn your actions into impact metrics to impress during QBR.', prompt: "You are a value selling expert. Help me quantify the value we delivered this quarter.\n\nAccount: [NAME]\nActions completed: [LIST OF ACTIONS/PROJECTS THIS QUARTER]\nAvailable metrics: [LIST]\n\nFor each action:\n1. Identify the most relevant impact metric\n2. Quantify in $ or % improvement\n3. Frame the impact statement (\"Thanks to X, you gained Y\")\n4. If no hard metric: suggest a credible proxy\n5. Summarize as a \"Total value delivered\" this quarter", tags: ['value', 'metrics', 'ROI'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'qbr-005', category: 'qbr', title: 'Recovery Plan After a Tough QBR', description: 'Your QBR went badly? Here is how to bounce back.', prompt: "You are a senior KAM who has handled crisis situations. My last QBR went badly.\n\nWhat happened: [SUMMARY]\nClient reactions: [SUMMARY]\nCurrent risk level: [1-10]\n\nCreate a recovery plan:\n1. Actions within 48 hours (damage control)\n2. Internal communication (escalation, support needed)\n3. 30-day reconquest plan\n4. Tracking metrics to measure recovery\n5. Follow-up email script after a difficult QBR", tags: ['crisis', 'recovery', 'follow-up'], difficulty: 'advanced', gordonBoost: true },
  { id: 'qbr-006', category: 'qbr', title: 'Turn QBR into a Sales Opportunity', description: 'Use QBR as a lever for commercial expansion.', prompt: "You are an account expansion expert. Help me subtly integrate sales opportunities into my next QBR.\n\nAccount: [NAME]\nCurrent products/services: [LIST]\nProducts to propose: [LIST]\n\nAdvise me:\n1. When during the QBR to introduce opportunities\n2. How to link them to quarterly results (\"since X worked, Y could...\")\n3. The exact wording to avoid seeming \"pushy\"\n4. How to get a concrete next step (not just \"we'll think about it\")\n5. The absolute trap to avoid in a QBR-sale", tags: ['expansion', 'sales', 'opportunity'], difficulty: 'advanced', gordonBoost: true },
  { id: 'qbr-007', category: 'qbr', title: 'Post-QBR Email Template', description: 'Send a professional follow-up after your QBR.', prompt: "You are an organized KAM. Write a post-QBR follow-up email.\n\nAccount: [NAME]\nQBR date: [DATE]\nParticipants: [LIST]\nDecisions made: [LIST]\nAgreed actions: [LIST WITH OWNERS]\n\nThe email should:\n1. Thank participants\n2. Summarize key points in bullet points\n3. List actions with owner + deadline\n4. Confirm the next QBR\n5. End on a positive and engaging note\n\nTone: professional, concise, actionable.", tags: ['email', 'follow-up', 'minutes'], difficulty: 'starter', gordonBoost: false },
  { id: 'qbr-008', category: 'qbr', title: 'QBR for a New Account', description: 'Structure your first QBR with a new client.', prompt: "You are a KAM consultant. This is my first QBR with this client. There is no history.\n\nAccount: [NAME]\nRelationship duration: [MONTHS]\nOnboarding completed: [YES/NO]\n\nHelp me:\n1. Structure a \"foundation\" QBR (vs a routine QBR)\n2. Questions to ask to establish the baseline\n3. How to define KPIs for the next quarters together\n4. Avoid the mistake of \"over-promising\" in the first QBR\n5. How to close with a strong mutual commitment", tags: ['first', 'onboarding', 'foundation'], difficulty: 'intermediate', gordonBoost: false },

  // CAPTURE PLAN (8)
  { id: 'cp-001', category: 'capture-plan', title: 'Strategic Capture Plan', description: 'Create a proactive retention plan to secure a renewal.', prompt: "You are a strategic retention expert. Help me build a Capture Plan.\n\nAccount: [NAME]\nAnnual revenue: [AMOUNT]\nRenewal date: [DATE]\nTime until renewal: [MONTHS]\n\nCreate a complete Capture Plan:\n1. Stakeholder map (who decides, who influences)\n2. Risk assessment (competitive, internal, budget)\n3. Value proposition to reinforce\n4. Action timeline (D-180, D-120, D-90, D-60, D-30)\n5. Communication strategy per stakeholder\n6. Plan B if renewal is threatened", tags: ['retention', 'renewal', 'capture'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'cp-002', category: 'capture-plan', title: 'Defend Against an Incoming Competitor', description: 'Your client is evaluating a competitor? Prepare your defensive strategy.', prompt: "You are a seasoned sales strategist. My client is evaluating a competitor to replace me.\n\nAccount: [NAME]\nCompetitor: [NAME]\nReason for evaluation: [PRICE / FEATURES / INTERNAL POLITICS / OTHER]\nDecision timeline: [DATE]\n\nProvide:\n1. Analysis of the client's real motivations\n2. Competitor strengths/weaknesses vs ours\n3. Defense strategy (3 scenarios)\n4. \"Switching cost\" argument\n5. Immediate actions (this week)\n6. Script for the next client meeting", tags: ['defense', 'competitor', 'retention'], difficulty: 'advanced', gordonBoost: true },
  { id: 'cp-003', category: 'capture-plan', title: 'Prepare the Renewal Pitch', description: 'Build a solid business case to justify renewal.', prompt: "You are a B2B value selling expert. Help me prepare my renewal pitch.\n\nAccount: [NAME]\nCurrent price: [AMOUNT]\nValue delivered this year: [SUMMARY]\nClient request: [DISCOUNT / SAME PRICE / INCREASE ACCEPTED]\n\nGenerate:\n1. Quantified business case (ROI, TCO, value delivered vs investment)\n2. 5 key arguments, ranked by impact\n3. Response to the price objection\n4. \"With us vs without us\" comparison (non-renewal scenario)\n5. Recommended renewal offer (structure)", tags: ['renewal', 'pricing', 'business case'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'cp-004', category: 'capture-plan', title: 'Handle a Sponsor Change', description: 'Your internal sponsor is leaving the client. How to secure the relationship?', prompt: "You are a senior KAM. My main sponsor at the client is leaving (promotion, resignation, reorg).\n\nAccount: [NAME]\nOutgoing sponsor: [NAME, ROLE]\nPotential replacement: [NAME, ROLE if known]\n\nAdvise me:\n1. Immediate actions (before departure)\n2. How to get an introduction to the replacement\n3. How to re-sell the value to a new decision-maker\n4. Pitfalls to avoid during transition\n5. Email script to the outgoing sponsor (requesting referral)\n6. Email script to the new contact (introduction)", tags: ['sponsor', 'transition', 'relationship'], difficulty: 'advanced', gordonBoost: true },
  { id: 'cp-005', category: 'capture-plan', title: 'Negotiate a Price Increase', description: 'Prepare and communicate a price increase to a strategic account.', prompt: "You are a B2B negotiation expert. I need to announce a price increase to a strategic account.\n\nAccount: [NAME]\nPlanned increase: [%]\nReason: [INFLATION / ADDED VALUE / MARKET ALIGNMENT]\nCurrent relationship: [GOOD / TENSE / NEUTRAL]\n\nGenerate:\n1. Optimal timing for the announcement\n2. Argument structure (justification + value)\n3. Conversation script\n4. Responses to the 5 most likely objections\n5. Possible concessions (without lowering the price)\n6. Plan B if the client categorically refuses", tags: ['pricing', 'negotiation', 'increase'], difficulty: 'advanced', gordonBoost: true },
  { id: 'cp-006', category: 'capture-plan', title: 'Identify Internal Champions', description: 'Spot and activate your allies at the client to secure the account.', prompt: "You are a complex sales expert. Help me identify and activate internal champions at my client.\n\nAccount: [NAME]\nCurrent contacts: [LIST WITH ROLES]\nRelationship history: [SUMMARY]\n\nProvide:\n1. Criteria to identify a true champion (vs a false ally)\n2. Questions to ask to test each contact's engagement\n3. How to turn a satisfied user into an active champion\n4. Champion mobilization plan before renewal\n5. How to reward/recognize your champions without crossing ethical lines", tags: ['champion', 'internal', 'mobilization'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'cp-007', category: 'capture-plan', title: 'Early Warning System for Churn', description: 'Set up an early detection system for churn risks.', prompt: "You are a Customer Success and KAM expert. Help me create an early warning system to detect churn risks.\n\nAccount type: [INDUSTRY / SIZE]\nCRM tools used: [LIST]\n\nCreate:\n1. List of 15 weak churn signals (behavioral, relational, contractual)\n2. Risk scoring: how to weight each signal\n3. Alert thresholds (green / amber / red)\n4. Automated actions per alert level\n5. Recommended tracking dashboard (key metrics)", tags: ['churn', 'alert', 'prevention'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'cp-008', category: 'capture-plan', title: 'Win Back a Lost Account', description: 'Strategy to recover a client who left you.', prompt: "You are a B2B win-back expert. One of my strategic accounts left us [DURATION] ago.\n\nAccount: [NAME]\nReason for departure: [SUMMARY]\nChosen competitor: [NAME]\nLost revenue: [AMOUNT]\n\nCreate a win-back strategy:\n1. Optimal timing to re-engage\n2. Approach angle (what has changed on our side)\n3. Intelligence gathering: how to find out if the competitor is disappointing\n4. Re-engagement script (email + phone)\n5. Recommended win-back offer\n6. 6-month timeline", tags: ['win-back', 'recovery', 'strategy'], difficulty: 'advanced', gordonBoost: true },

  // OBJECTIONS (9)
  { id: 'obj-001', category: 'objections', title: 'Handle the Price Objection in Enterprise', description: 'Respond with confidence when a decision-maker challenges your price.', prompt: "You are an enterprise negotiation expert. My client says: \"You're too expensive.\"\n\nContext: [SITUATION DESCRIPTION]\nProposed price: [AMOUNT]\nCheaper competitor: [YES/NO, NAME if known]\n\nProvide:\n1. The 3 most effective response techniques in B2B\n2. How to reframe the debate from price → value\n3. Questions to ask to understand the real objection behind the price\n4. Response script (word for word)\n5. What you should NEVER say when facing this objection", tags: ['price', 'negotiation', 'objection'], difficulty: 'starter', gordonBoost: true },
  { id: 'obj-002', category: 'objections', title: '"We\'re Going to Run an RFP"', description: 'Your client wants to put you in competition. How to react?', prompt: "You are a B2B sales strategist. My client announces an RFP for the renewal.\n\nAccount: [NAME]\nLikely motivation: [INTERNAL POLITICS / PRICE / GENUINE NEED FOR CHANGE]\n\nAdvise me:\n1. How to react in the meeting (attitude, words)\n2. The 3 questions to ask immediately\n3. How to influence the RFP requirements in your favor\n4. Strategy if the RFP is unavoidable vs if it can be avoided\n5. How to mobilize your internal champions during the RFP", tags: ['RFP', 'competition', 'strategy'], difficulty: 'advanced', gordonBoost: true },
  { id: 'obj-003', category: 'objections', title: '"I Need to Check with My Manager"', description: "The contact doesn't have decision-making authority. How to move forward?", prompt: "You are a complex sales coach. My contact says: \"I need to run this by my manager / the committee.\"\n\nContext: [DESCRIPTION]\nWhat you're selling: [SUMMARY]\n\nProvide:\n1. How to assess if it's a real objection or a brush-off\n2. How to arm your champion to sell internally\n3. The document/email your contact can forward to their manager\n4. How to propose a meeting with the decision-maker without going over heads\n5. Immediate response script", tags: ['decision-maker', 'champion', 'escalation'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'obj-004', category: 'objections', title: '"We\'re Happy with Our Current Solution"', description: "The client sees no reason to change. How to create doubt?", prompt: "You are a consultative selling expert. My prospect says: \"We're happy with our current provider.\"\n\nTheir provider: [NAME if known]\n\nProvide:\n1. Why this objection is actually an opportunity\n2. The 5 questions that create doubt without being aggressive\n3. How to introduce the concept of \"cost of inaction\"\n4. Examples of transitions that worked in similar cases\n5. The \"keep your solution, add ours\" strategy (land and expand)", tags: ['status quo', 'change', 'prospecting'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'obj-005', category: 'objections', title: '"The Timing Isn\'t Right"', description: 'The client is postponing the decision. How to create urgency?', prompt: "You are a B2B closing expert. My client says: \"Not now, come back in 6 months.\"\n\nContext: [DESCRIPTION]\nStated reason: [BUDGET / REORG / PRIORITIES]\n\nProvide:\n1. How to distinguish a real timing issue from an unspoken objection\n2. Techniques to create urgency without being pushy\n3. How to stay top-of-mind during the wait\n4. Optimal follow-up schedule (frequency, channel, content)\n5. \"Pre-commitment\" offer to secure the future deal", tags: ['timing', 'urgency', 'follow-up'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'obj-006', category: 'objections', title: 'Handle Procurement Objections', description: 'Procurement has their own tactics. Be prepared.', prompt: "You are a B2B procurement negotiation expert. I'm about to meet my client's Procurement team.\n\nAccount: [NAME]\nDeal amount: [AMOUNT]\nLikely procurement tactics: [DISCOUNT REQUEST / COMPETITIVE BID / EXTENDED PAYMENT TERMS]\n\nPrepare me:\n1. The 7 classic procurement tactics and how to respond\n2. How to defend the price without damaging the relationship\n3. Non-price concessions to offer (scope, timeline, services)\n4. When to escalate to the business owner\n5. Red flags indicating the deal is at risk", tags: ['procurement', 'negotiation', 'tactics'], difficulty: 'advanced', gordonBoost: true },
  { id: 'obj-007', category: 'objections', title: '"Your Competitor Offers More Features"', description: 'The client is comparing feature by feature. How to reframe?', prompt: "You are a competitive positioning expert. My client says: \"Your competitor [NAME] offers X, Y, Z that you don't have.\"\n\nMissing features cited: [LIST]\n\nProvide:\n1. How to reframe the debate from features → business outcomes\n2. Argument: \"Why fewer features can be an advantage\"\n3. Questions to ask to understand the real need behind the feature\n4. The \"future roadmap\" technique (without over-promising)\n5. When to concede and when to hold your position", tags: ['features', 'competition', 'positioning'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'obj-008', category: 'objections', title: '"We Don\'t Have the Budget"', description: 'The most classic budget objection. How to overcome it?', prompt: "You are a B2B budget justification expert. My client says: \"We don't have the budget this year.\"\n\nOur solution cost: [AMOUNT]\nClient budget for this type of solution: [KNOWN/UNKNOWN]\n\nProvide:\n1. 4 techniques to \"find\" budget at the client\n2. How to build a business case that convinces the CFO\n3. Structuring alternatives (installments, deferred payment, reduced phase 1)\n4. Questions that reveal whether budget is a real obstacle or a pretext\n5. Budget justification email template for your champion", tags: ['budget', 'ROI', 'justification'], difficulty: 'starter', gordonBoost: true },
  { id: 'obj-009', category: 'objections', title: '"We\'ll Build It In-House"', description: 'The client wants to build rather than buy. How to respond?', prompt: "You are a solutions vs build sales expert. My client says: \"We prefer to develop this in-house.\"\n\nWhat we sell: [DESCRIPTION]\nClient's internal capabilities: [SUMMARY]\n\nProvide:\n1. Complete Buy vs Build analysis (hidden costs of building)\n2. The 5 most compelling arguments for Buy\n3. How to quantify the opportunity cost of in-house development\n4. Typical case study: \"They tried in-house and came back to us\"\n5. The smart compromise: \"Build X, buy Y\" (coexistence strategy)", tags: ['build vs buy', 'in-house', 'ROI'], difficulty: 'intermediate', gordonBoost: false },

  // RELATIONSHIP MAPPING (8)
  { id: 'rm-001', category: 'relationship-mapping', title: 'Map Decision-Makers', description: 'Identify who really decides at your client.', prompt: "You are a complex B2B sales expert. Help me map the decision-makers for this account.\n\nAccount: [NAME]\nDecision type: [INITIAL PURCHASE / RENEWAL / EXPANSION]\nEstimated budget: [AMOUNT]\n\nFor each typical role (Executive Sponsor, Technical Decision-Maker, End User, Buyer, Influencer), provide:\n1. Likely title in the org chart\n2. Specific decision criteria\n3. Likely objections\n4. Tailored key message\n5. Required engagement level (low/medium/high)", tags: ['decision-makers', 'mapping', 'roles'], difficulty: 'starter', gordonBoost: false },
  { id: 'rm-002', category: 'relationship-mapping', title: 'Identify Blockers', description: 'Spot internal resistance at the client.', prompt: "You are a complex sales strategist. Help me identify and manage potential blockers.\n\nAccount: [NAME]\nOngoing project/deal: [DESCRIPTION]\nSuspected blockers: [NAMES/ROLES if known]\n\nProvide:\n1. The 5 typical blocker profiles in B2B sales\n2. Signals indicating a contact is a blocker\n3. Strategies for each blocker profile\n4. How to neutralize a blocker without conflict\n5. When to ignore a blocker vs when to confront them", tags: ['blocker', 'resistance', 'politics'], difficulty: 'advanced', gordonBoost: true },
  { id: 'rm-003', category: 'relationship-mapping', title: 'Multi-Threading Strategy', description: 'Develop contacts across multiple hierarchical levels.', prompt: "You are a strategic account management expert. I only have one contact at this client. This is risky.\n\nAccount: [NAME]\nSole contact: [NAME, ROLE]\nLevels to cover: [OPERATIONAL / MANAGEMENT / EXECUTIVE]\n\nCreate a multi-threading plan:\n1. Why a single contact is the biggest risk in KAM\n2. Strategy to get introductions without going over heads\n3. Events/pretexts to meet other levels\n4. Email template to request an introduction\n5. 90-day coverage target (number of contacts per level)", tags: ['multi-thread', 'contacts', 'risk'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'rm-004', category: 'relationship-mapping', title: 'Understand Internal Politics', description: "Decode the power dynamics at your client.", prompt: "You are a B2B political selling advisor. Help me understand the internal politics of this account.\n\nAccount: [NAME]\nRecent events: [REORG / MERGER / NEW CEO / OTHER]\nObserved tensions: [BETWEEN WHOM]\n\nAnalyze:\n1. How these changes impact our position\n2. The winners and losers of the situation\n3. Where to position ourselves in this new landscape\n4. Alliances to form and those to avoid\n5. The #1 political trap to avoid in KAM", tags: ['politics', 'power', 'dynamics'], difficulty: 'advanced', gordonBoost: false },
  { id: 'rm-005', category: 'relationship-mapping', title: 'Build a C-Level Relationship', description: 'Access and maintain a relationship with executives.', prompt: "You are an executive selling expert. I want to build a relationship with my client's C-level.\n\nAccount: [NAME]\nTarget C-level: [TITLE: CEO, CFO, CTO, COO...]\nCurrent relationship: [NONE / DISTANT / DECENT]\n\nAdvise me:\n1. The 3 channels to reach the C-level (LinkedIn, event, introduction)\n2. What a C-level cares about (vs an operational manager)\n3. How to deliver value BEFORE asking for anything\n4. Ideal contact frequency with a C-level\n5. Executives' preferred communication format\n6. Fatal mistakes that lose you C-level access", tags: ['C-level', 'executive', 'relationship'], difficulty: 'advanced', gordonBoost: true },
  { id: 'rm-006', category: 'relationship-mapping', title: 'Plan a Client Event', description: 'Plan a strategic event to strengthen relationships.', prompt: "You are a B2B client relationship expert. I want to organize an event for my key contacts at this account.\n\nAccount: [NAME]\nNumber of contacts to invite: [N]\nBudget: [AMOUNT]\nObjective: [STRENGTHEN / EXPAND / CELEBRATE]\n\nPropose:\n1. 3 event formats suited to the context\n2. Ideal program (timing, content, networking)\n3. How to select the right guests\n4. Key messages to convey during the event\n5. Post-event follow-up (within 48 hours)", tags: ['event', 'networking', 'relationship'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'rm-007', category: 'relationship-mapping', title: 'Quarterly Contact Plan', description: 'Structure your interactions across all account levels.', prompt: "You are a methodical KAM. Create a quarterly contact plan for this account.\n\nAccount: [NAME]\nCurrent contacts: [LIST WITH NAME, ROLE, LEVEL]\nCurrent frequency: [SUMMARY]\n\nGenerate a plan:\n1. Table: Contact / Frequency / Format / Objective\n2. Key events of the quarter (QBR, contract anniversary, etc.)\n3. Content to share by level (C-level: market insights, Ops: best practices, Tech: roadmap)\n4. Tracking metrics (NPS, sentiment, engagement)\n5. \"Surprise and delight\" actions (small gestures with big impact)", tags: ['plan', 'contacts', 'quarterly'], difficulty: 'starter', gordonBoost: false },
  { id: 'rm-008', category: 'relationship-mapping', title: 'Manage Relationships During a Crisis', description: 'Maintain trust when things go wrong.', prompt: "You are a B2B crisis management expert. We have a major incident with this client.\n\nAccount: [NAME]\nIncident: [DESCRIPTION]\nClient impact: [DESCRIPTION]\nClient reaction: [ANGER / DISAPPOINTMENT / THREAT]\n\nAdvise me:\n1. The 5 golden rules of crisis communication in KAM\n2. Emergency call script (within the hour)\n3. Follow-up email (within 4 hours)\n4. Resolution plan with transparent timeline\n5. How to turn this crisis into a relationship-strengthening moment", tags: ['crisis', 'incident', 'trust'], difficulty: 'advanced', gordonBoost: true },

  // SCORING (8)
  { id: 'sc-001', category: 'scoring', title: 'Client Potential Scoring', description: 'Assess the strategic potential of your accounts.', prompt: "You are a KAM analyst. Help me score this account's potential across 6 dimensions.\n\nAccount: [NAME]\nIndustry: [INDUSTRY]\nCurrent revenue: [AMOUNT]\nCompany size: [HEADCOUNT]\n\nScore each dimension from 1 to 5 and justify:\n1. Revenue potential (wallet size)\n2. Strategic fit (alignment with our offering)\n3. Relationship strength (access, trust)\n4. Growth probability (account trend)\n5. Competitive position (our advantage)\n6. Decision timeline (urgency/next steps)\n\nTotal score /30 + recommendation (Invest / Maintain / Divest)", tags: ['scoring', 'potential', 'prioritization'], difficulty: 'starter', gordonBoost: false },
  { id: 'sc-002', category: 'scoring', title: 'Segment Your Portfolio', description: 'Classify your accounts into strategic tiers.', prompt: "You are a sales strategy consultant. Help me segment my account portfolio.\n\nNumber of accounts: [N]\nTotal revenue: [AMOUNT]\nCurrent time allocation: [SUMMARY]\n\nProvide:\n1. Recommended segmentation criteria (Pareto, strategic, potential)\n2. Definition of each tier: Platinum / Gold / Silver / Bronze\n3. Recommended time allocation per tier\n4. Typical actions per tier (contact frequency, QBR type, investment)\n5. How to communicate the segmentation internally (to your manager)", tags: ['segmentation', 'portfolio', 'tiers'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'sc-003', category: 'scoring', title: 'Portfolio Pareto Analysis', description: 'Apply the 80/20 rule to your portfolio.', prompt: "You are a sales analyst. Help me apply the Pareto principle to my portfolio.\n\nTotal number of accounts: [N]\nAccount list with revenue: [FORMAT: Name — Revenue]\n\nAnalyze:\n1. Identify the 20% generating 80% of revenue\n2. Identify high-potential under-invested accounts\n3. Identify time-consuming low-revenue accounts\n4. Time reallocation recommendation\n5. Concrete actions: which accounts to intensify, which to delegate", tags: ['Pareto', '80/20', 'reallocation'], difficulty: 'starter', gordonBoost: false },
  { id: 'sc-004', category: 'scoring', title: 'Risk Scoring by Account', description: 'Identify the highest-risk accounts in your portfolio.', prompt: "You are a commercial risk management expert. Help me score the risk of my accounts.\n\nAccount list: [FORMAT: Name — Revenue — Renewal date — Comment]\n\nFor each account, assess risk (1-10) on:\n1. Contractual risk (renewal date, clauses)\n2. Relationship risk (single-contact dependency, turnover)\n3. Competitive risk (competitor aggressiveness)\n4. Satisfaction risk (incidents, NPS, feedback)\n5. Economic risk (client's financial health)\n\nFinal ranking by overall risk + top 3 mitigation actions", tags: ['risk', 'scoring', 'mitigation'], difficulty: 'intermediate', gordonBoost: true },
  { id: 'sc-005', category: 'scoring', title: 'Attractiveness vs Position Matrix', description: 'Position your accounts on the classic strategic matrix.', prompt: "You are a sales strategist. Help me build an Attractiveness vs Position strength matrix.\n\nAccounts to position: [LIST WITH REVENUE AND COMMENT]\n\nFor each account:\n1. Attractiveness score (1-10): size, growth, margin, prestige\n2. Position score (1-10): wallet share, relationship, competitive advantage\n3. Placement in the 2x2 matrix\n4. Strategy per quadrant:\n   - High attractiveness + Strong position → Invest\n   - High attractiveness + Weak position → Develop\n   - Low attractiveness + Strong position → Defend/Monetize\n   - Low attractiveness + Weak position → Disengage", tags: ['matrix', 'strategy', 'attractiveness'], difficulty: 'intermediate', gordonBoost: false },
  { id: 'sc-006', category: 'scoring', title: 'Calculate Customer Lifetime Value', description: 'Estimate the lifetime value of your strategic accounts.', prompt: "You are a commercial finance analyst. Help me calculate the CLV of my key accounts.\n\nAccount: [NAME]\nCurrent annual revenue: [AMOUNT]\nGross margin: [%]\nAverage relationship duration in this industry: [YEARS]\nEstimated annual growth rate: [%]\nAnnual cost to serve: [AMOUNT]\n\nCalculate:\n1. Simple CLV (Revenue × margin × duration)\n2. CLV with growth (incorporating growth rate)\n3. Net CLV (after cost to serve)\n4. Comparison with acquisition cost\n5. Investment recommendation based on CLV", tags: ['CLV', 'value', 'financial'], difficulty: 'advanced', gordonBoost: false },
  { id: 'sc-007', category: 'scoring', title: 'Prioritize This Week\'s Actions', description: 'Decide where to invest your time this week.', prompt: "You are a KAM productivity coach. Help me prioritize my actions this week.\n\nMy accounts and situations:\n[FORMAT PER ACCOUNT: Name — Revenue — Current situation — Planned action]\n\nUsing the Urgency/Impact matrix, classify each action as:\n1. Do immediately (urgent + high impact)\n2. Schedule (not urgent + high impact)\n3. Delegate (urgent + low impact)\n4. Eliminate (not urgent + low impact)\n\nPropose a weekly schedule (Monday to Friday) with allocated time slots.", tags: ['priority', 'weekly', 'productivity'], difficulty: 'starter', gordonBoost: false },
  { id: 'sc-008', category: 'scoring', title: 'Internal Account Benchmark', description: 'Compare your accounts to identify best practices.', prompt: "You are a sales performance consultant. Help me benchmark my accounts.\n\nAccounts to compare: [FORMAT: Name — Revenue — Margin — Tenure — NPS]\n\nProvide:\n1. Comparison table across 6 metrics\n2. Identification of the \"model account\" (best-in-class)\n3. What makes this model account different\n4. Actions to replicate this success across other accounts\n5. The 3 most impactful quick wins", tags: ['benchmark', 'comparison', 'best practice'], difficulty: 'intermediate', gordonBoost: false },
]

export function getPrompts(lang: 'fr' | 'en'): Prompt[] {
  return lang === 'fr' ? promptsFR : promptsEN
}
